{
  "verses": [
    {
      "n": 12,
      "column": "left",
      "text": "Reggi Deew̄ irr aug-\ncham Debbeſis ? reds jelle to\nSwaigſnu Augſtumu / ka tah̄\ner augſti liktas.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tatschu tu faſki: Ko tas\nSTIPRAIG DEEWS\nvar to finn? woj wiꞥſch mah̄ to/\nas Tumfibā/ teefacht?\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Tah̄ Padebbeſis irr\nwiınna Aiſegs/ ka tas ne reds/\nn wiꞥſch staiga eekſch Debbe-\nim.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Gribbi tu to Zeffu tah̄\npirmas Baſaules turreht/ us ko\nee netaitnt Laudis gahjuschi?\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Kas pirms Laika irr no-\nihkuschi / ta Straume irr pahr\nwizanu Bannatteem iṣahſta.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Kas uē to STIPRII\nDEEWU fazzija: Atkahpees no\nmums/ ko buhtu tas Wiſfuwar-\nenajs teem darrije?\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Kur tomehr tas wiınnu\nMammus ar Labbumu bij vil-\ndijs/ tapehz lai to Besdeewigu\nPadohms tah̄tu no mammim\npaleek.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Tee Taisnee to reds un\npreezajahs/ un tas Nenoseedsigs\ntoh̄ apmehd.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Gann redſeti / wiınnu\nBuhſchana eeṣ bohjā/ un kas no\nteem atleek/ to aprihs tas Ug-\nguns.\n"
    },
    {
      "n": 21,
      "column": "left",
      "text": "Raddinajes jelle pee\nwiınna/ un paleez ar Meeru / no\ntatew dands Labbuma nahktees.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Nemm jelle to Bauſlibu\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Ja tu pee ta Wiſfuwar-\nrena atgreeſifees/ tad tapſi tu\nustaifhts/ atmett to Metaifni-\nbu tah̄tu no tawa Dſihwokta.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Tad krahſi tu Seltu ka\nPihtschlus/ un Selta Uppeṣ(tik\ndauds) ka Akminus.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un tas Wiſfuwarrenajs\nbuhs teu par Selta Kohpu/ un\nbuhs teu par fpohſchu Sudrabi.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Tad tu pahr to Wiſfu-\nwarreno preezafees / un pazelfi\nus Deewu tah̄u Waigu.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Tu peefauſti wiınnu / un\nwiꞥſch teu paklantibs / un tu\nmakfaſi tawas Apfohſſchanas.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Rad tu tahdu Leetu ap-\nneimmes/ tad ta teu pastah-\nwehs/un ue taiweem Zeffeemi tas\nGaifchungs fpihdehs.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Rad kas paſemmo / tad\ntu fazziti: Tas buhs par Pa-\naugſtinachanu / un wiꞥſch to/\nkam noskummis Waigs irr/ iṣ-\nglahbs.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Wiꞥſch (arri) to ispe-\nſiifs/ kas neeka ne noseedsis/ tas\npats Jawu Rohku Schkihſtibas\ndeht taps ispeſtihts.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
